const query = ($('Trigger').first().json.query || '').toString().trim();
const rawText = ($input.first().json.data || '').toString();

function normalizeFractions(str) {
  str = String(str || '');
  // Primero fracciones mixtas: "1 1/2" antes que "1/2"
  str = str.replace(/(\d+)\s+(\d+)\/(\d+)/g, (_, w, n, d) => {
    const v = Math.round((parseInt(w) + parseInt(n) / parseInt(d)) * 100);
    return 'frac' + String(v).padStart(3, '0');
  });
  // Luego fracciones simples: "1/2"
  str = str.replace(/(\d+)\/(\d+)/g, (_, n, d) => {
    const v = Math.round((parseInt(n) / parseInt(d)) * 100);
    return 'frac' + String(v).padStart(3, '0');
  });
  return str;
}

function normalize(str) {
  return normalizeFractions(str)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

let data;
try {
  const jsonStr = rawText.replace(/^[^(]+\(/, '').replace(/\);?\s*$/, '');
  data = JSON.parse(jsonStr);
} catch(e) {
  return [{ json: { response: '⚠️ Error parseando precios: ' + e.message } }];
}

const cols = data.table.cols.map(c => (c.label || c.id || '').trim().replace(/\s+/g, ' '));
const rows = (data.table.rows || [])
  .map(row => {
    const obj = {};
    (row.c || []).forEach((cell, i) => { if (cols[i]) obj[cols[i]] = cell && cell.v !== null ? cell.v : ''; });
    return obj;
  })
  .filter(r => r['Material']);

const normQuery = normalize(query);
const STOP = new Set(['de','el','la','los','las','un','una','en','con','del','por','que','al','se','psi']);
const tokens = normQuery.split(' ')
  .filter(t => t.length >= 2 || /^\d+$/.test(t))
  .filter(t => !STOP.has(t));

if (tokens.length === 0) {
  return [{ json: { response: '❓ ¿De qué producto necesitas el precio?' } }];
}

const scored = rows.map(row => {
  const combined = normalize(String(row['Material'] || '')) + ' ' + normalize(String(row['Descripcion'] || ''));
  const hits = tokens.filter(t => combined.includes(t)).length;
  return { row, hits, score: hits / tokens.length };
}).filter(r => r.hits > 0).sort((a, b) => b.score - a.score || b.hits - a.hits);

if (scored.length === 0) {
  return [{ json: { response: `❌ No encontré precio para "${query}". ¿Puedes describirlo de otra forma?` } }];
}

const threshold = scored[0].score * 0.75;
const candidates = scored.filter(r => r.score >= threshold);

if (candidates.length > 3) {
  const opts = candidates.slice(0, 6).map((r, i) => `${i+1}. ${r.row['Material']} — ${r.row['Descripcion']}`).join('\n');
  return [{ json: { response: `🔍 ${candidates.length} resultados con "${query}":\n\n${opts}\n\n¿Cuál necesitas?` } }];
}

const lines = candidates.slice(0, 3).map(r => {
  const d = r.row;
  const precio = String(d['Precio Sin Iva'] || '').trim();
  const precioNum = parseFloat(String(precio).replace(/\./g, '').replace(',', '.'));
  const precioText = precio && !isNaN(precioNum) && !String(precio).toLowerCase().includes('confirm')
    ? `Bs. ${precioNum.toLocaleString('es-VE')}`
    : '⚠️ Consultar con jefe de ventas';
  const aaap = parseFloat(d['AAA+']);
  const aaa  = parseFloat(d['AAA']);
  const aa   = parseFloat(d['AA']);
  const a    = parseFloat(d['A']);
  const descParts = [
    !isNaN(aaap) && `AAA+:${aaap}%`,
    !isNaN(aaa)  && `AAA:${aaa}%`,
    !isNaN(aa)   && `AA:${aa}%`,
    !isNaN(a)    && `A:${a}%`
  ].filter(Boolean);
  return `💰 ${d['Material']} | ${d['Descripcion']}\n  Lista (sin IVA): ${precioText}\n  Descuentos: ${descParts.join(' | ')}`;
});

return [{ json: { response: lines.join('\n\n') } }];
